content:
{
  "sentences": [
    {
      "text": "我因為肚子餓，所以想吃飯。",
      "pinyin": "Wǒ yīnwèi dùzi è, suǒyǐ xiǎng chī fàn.",
      "pinyin_numeric": "wo3 yin1 wei4 du4 zi5 e4, suo3 yi3 xiang3 chi1 fan4.",
      "translation_en": "I am hungry, so I want to eat.",
      "translation_ko": "저는 배가 고파서 밥을 먹고 싶어요."
    },
    {
      "text": "他因為口渴，所以想喝一杯水。",
      "pinyin": "Tā yīnwèi kǒukě, suǒyǐ xiǎng hē yī bēi shuǐ.",
      "pinyin_numeric": "ta1 yin1 wei4 kou3 ke3, suo3 yi3 xiang3 he1 yi1 bei1 shui3.",
      "translation_en": "He is thirsty, so he wants to drink a glass of water.",
      "translation_ko": "그는 목이 말라서 물 한 잔을 마시고 싶어요."
    },
    {
      "text": "她因為感冒了，所以不想喝冰的飲料。",
      "pinyin": "Tā yīnwèi gǎnmào le, suǒyǐ bù xiǎng hē bīng de yǐnliào.",
      "pinyin_numeric": "ta1 yin1 wei4 gan3 mao4 le5, suo3 yi3 bu4 xiang3 he1 bing1 de5 yin3 liao4.",
      "translation_en": "She has a cold, so she doesn't want to drink cold drinks.",
      "translation_ko": "그녀는 감기에 걸려서 차가운 음료를 마시고 싶지 않아요."
    },
    {
      "text": "我們因為太累了，所以想休息一下。",
      "pinyin": "Wǒmen yīnwèi tài lèi le, suǒyǐ xiǎng xiūxí yīxià.",
      "pinyin_numeric": "wo3 men5 yin1 wei4 tai4 lei4 le5, suo3 yi3 xiang3 xiu1 xi2 yi1 xia4.",
      "translation_en": "We are too tired, so we want to rest for a while.",
      "translation_ko": "저희는 너무 피곤해서 잠시 쉬고 싶어요."
    },
    {
      "text": "你因為沒睡飽，所以不想去上班嗎？",
      "pinyin": "Nǐ yīnwèi méi shuì bǎo, suǒyǐ bù xiǎng qù shàngbān ma?",
      "pinyin_numeric": "ni3 yin1 wei4 mei2 shui4 bao3, suo3 yi3 bu4 xiang3 qu4 shang4 ban1 ma5?",
      "translation_en": "Are you not going to work because you didn't get enough sleep?",
      "translation_ko": "잠을 충분히 못 자서 출근하고 싶지 않으세요?"
    },
    {
      "text": "我因為想省錢，所以不想買那個手機。",
      "pinyin": "Wǒ yīnwèi xiǎng shěng qián, suǒyǐ bù xiǎng mǎi nàge shǒujī.",
      "pinyin_numeric": "wo3 yin1 wei4 xiang3 sheng3 qian2, suo3 yi3 bu4 xiang3 mai3 na4 ge5 shou3 ji1.",
      "translation_en": "I want to save money, so I don't want to buy that phone.",
      "translation_ko": "돈을 아끼고 싶어서 그 핸드폰을 사고 싶지 않아요."
    },
    {
      "text": "他因為忘記帶錢，所以不能買咖啡。",
      "pinyin": "Tā yīnwèi wàngjì dài qián, suǒyǐ bù néng mǎi kāfēi.",
      "pinyin_numeric": "ta1 yin1 wei4 wang4 ji4 dai4 qian2, suo3 yi3 bu4 neng2 mai3 ka1 fei1.",
      "translation_en": "He forgot to bring money, so he can't buy coffee.",
      "translation_ko": "그는 돈을 가져오는 것을 잊어서 커피를 살 수 없어요."
    },
    {
      "text": "她因為剛下班，所以想先回家休息。",
      "pinyin": "Tā yīnwèi gāng xiàbān, suǒyǐ xiǎng xiān huí jiā xiūxí.",
      "pinyin_numeric": "ta1 yin1 wei4 gang1 xia4 ban1, suo3 yi3 xiang3 xian1 hui2 jia1 xiu1 xi2.",
      "translation_en": "She just got off work, so she wants to go home and rest first.",
      "translation_ko": "그녀는 방금 퇴근해서 먼저 집에 가서 쉬고 싶어요."
    },
    {
      "text": "我們因為塞車了，所以來不及吃早餐。",
      "pinyin": "Wǒmen yīnwèi sāichē le, suǒyǐ láibují chī zǎocān.",
      "pinyin_numeric": "wo3 men5 yin1 wei4 sai1 che1 le5, suo3 yi3 lai2 bu5 ji2 chi1 zao3 can1.",
      "translation_en": "We were stuck in traffic, so we didn't have time to eat breakfast.",
      "translation_ko": "저희는 교통 체증이 있어서 아침을 먹을 시간이 없었어요."
    },
    {
      "text": "你因為生病了，所以不想喝咖啡嗎？",
      "pinyin": "Nǐ yīnwèi shēngbìng le, suǒyǐ bù xiǎng hē kāfēi ma?",
      "pinyin_numeric": "ni3 yin1 wei4 sheng1 bing4 le5, suo3 yi3 bu4 xiang3 he1 ka1 fei1 ma5?",
      "translation_en": "Are you sick, so you don't want to drink coffee?",
      "translation_ko": "아파서 커피를 마시고 싶지 않으세요?"
    }
  ]
}
